std::vector<std::vector<double>> eigen_to_vector(const Eigen::MatrixXd& mat) {
    std::vector<std::vector<double>> vec(mat.rows(), std::vector<double>(mat.cols()));

    for (std::size_t i = 0; i < mat.rows(); ++i) {
        for (std::size_t j = 0; j < mat.cols(); ++j) {
            vec[i][j] = mat(i, j);
        }
    }
    return vec;
}


inline std::string format_double(double value, int precision = 2) {
    std::ostringstream oss;
    oss << std::fixed << std::setprecision(precision) << value;
    return oss.str();
}


void center_and_l2_normalize(Eigen::MatrixXd& X) {
    // Centering
    Eigen::RowVectorXd mean = X.colwise().mean();
    X.rowwise() -= mean;

    // L2 Normalization
    for (std::size_t j = 0; j < X.cols(); ++j) {
        double norm = X.col(j).norm();
        if (norm > 0) {
            X.col(j) /= norm;
        }
    }
}


void demo_visualize_constrained_sparse_rademacher_matrix() {

   // Create a correlation matrix or data
   const std::size_t n = 300;
   const std::size_t p = 1000;
   const std::vector<double> sparsity_density_vec = {0.01, 0.1, 0.2, 0.3, 0.5, 0.9};

   for (double sparsity_density : sparsity_density_vec) {

        Eigen::MatrixXd X(n, p);

        // Create distribution and fill matrix
        auto dist = dummygen::Distribution::ConstrainedSparseRademacher(sparsity_density);
        dummygen::generate_dummies(X, X.rows(), X.cols(), std::random_device{}(), dist);
        center_and_l2_normalize(X);

        std::vector<std::vector<double>> X_mat = eigen_to_vector(X);

        plt::imagesc(X_mat);
        plt::colorbar();

        std::string fig_title = "Constrained-Sparsity Rademacher Dummy Matrix "
                    "(n = " + std::to_string(n) + ", p=" + std::to_string(p) + ", s=" +
                    format_double(sparsity_density, 2) + ")";
        plt::title(fig_title);

        std::string filename = "./simulations/dummymat_constrained_sparsity_rademacher_n_" +
                            std::to_string(n) + "_p_" +
                            std::to_string(p) + "_s_" +
                            format_double(sparsity_density, 2) + ".png";
        plt::save(filename);
    }
}


