// 2. Plotting Logic (Matplot++)
// ===========================================================================
void plotRMatrix(const Eigen::MatrixXd& R_mat, const std::vector<double>& V_grid) {
    using namespace matplot;

    std::size_t n_steps = R_mat.rows();
    std::size_t n_thresholds = R_mat.cols();

    // Setup X-Axis: T = 1, 2, ..., 49
    std::vector<double> t_steps(n_steps);
    std::iota(t_steps.begin(), t_steps.end(), 1.0);

    auto f = figure(true);
    f->size(1200, 800);
    hold(on);

    // --- PLOTTING STRATEGY ---
    // We plot 3 lines to show the "Stagnation" across different stringency levels:
    // 1. Loose (v=0.5): Shows what happens when we accept "unstable" noise.
    // 2. Strict (v=0.95): Shows the behavior of the "Dominant Signal".

    // Indices for V_grid = {0.50, ..., 0.95} (Size 10)
    std::vector<size_t> cols_to_plot = {0, 4, 9}; // v=0.50, v=0.70, v=0.95
    std::vector<std::string> colors = {"blue", "orange", "red"};
    std::vector<std::string> line_styles = {"--", "-.", "-"};

    for (size_t i = 0; i < cols_to_plot.size(); ++i) {
        size_t col_idx = cols_to_plot[i];

        // Extract column
        std::vector<double> r_series;
        for (size_t r = 0; r < n_steps; ++r) {
            r_series.push_back(R_mat(r, col_idx));
        }

        // Plot
        auto l = plot(t_steps, r_series);
        l->line_width(3.0);
        l->color(colors[i]);
        l->line_style(line_styles[i]);

        std::stringstream label;
        label << "Voting Threshold v=" << std::fixed << std::setprecision(2) << V_grid[col_idx];
        l->display_name(label.str());
    }

    // --- ANNOTATION ---
    double max_r = R_mat.col(9).maxCoeff(); // Max R for strict threshold

    // Use simple text arrow (without modifying object properties)
    // textarrow(x_tail, y_tail, x_head, y_head, text)
    textarrow(20, max_r + 0.5, 40, max_r + 0.1, "Stagnation (Flatline)");

    // Styling
    title("Evidence of Greedy Stagnation: Consensus Set Size (R) vs. T");
    xlabel("Number of Dummies (T)");
    ylabel("Number of Selected Variables (R)");

    double absolute_max_r = R_mat.maxCoeff();
    ylim({0, absolute_max_r + 1.5});

    grid(on);
    legend()->location(legend::general_alignment::bottomright);

    // Correct way to set font size on the current axes
    gca()->font_size(14.0);

    show();
}

