void plotPhiMatrix(const Eigen::MatrixXd& Phi) {
    using namespace matplot;

    std::size_t n_steps = Phi.rows();
    std::size_t p = Phi.cols();

    // Setup X-Axis
    std::vector<double> t_steps(n_steps);
    std::iota(t_steps.begin(), t_steps.end(), 1.0);

    // --- SORT VARIABLES BY FINAL STABILITY ---
    std::vector<int> indices(p);
    std::iota(indices.begin(), indices.end(), 0);

    // Sort descending based on the value in the LAST row
    std::sort(indices.begin(), indices.end(), [&](int a, int b) {
        return Phi(n_steps - 1, a) > Phi(n_steps - 1, b);
    });

    auto f = figure(true);
    f->size(1200, 700);
    hold(on);

    // Colors for the top ranked variables
    std::vector<std::string> colors = {"red", "blue", "green", "magenta", "cyan"};

    // 1. Plot the Top 5 Candidates (Rank 1, 2, 3, 4, 5)
    int top_k = 5;
    for (int i = 0; i < top_k; ++i) {
        int idx = indices[i];

        std::vector<double> curve;
        for (size_t t = 0; t < n_steps; ++t) curve.push_back(Phi(t, idx));

        auto l = plot(t_steps, curve);
        l->line_width(3.0);
        l->color(colors[i % colors.size()]);

        std::stringstream ss;
        ss << "Rank " << (i+1) << " (Col " << idx << ")";
        l->display_name(ss.str());
    }

    // 2. Plot the Noise Floor (Max of the rest)
    if (p > top_k) {
        std::vector<double> noise_floor;
        for (size_t t = 0; t < n_steps; ++t) {
            double max_val = 0.0;
            // Scan all variables NOT in the top K
            for (int i = top_k; i < p; ++i) {
                double val = Phi(t, indices[i]);
                if (val > max_val) max_val = val;
            }
            noise_floor.push_back(max_val);
        }

        auto l_noise = plot(t_steps, noise_floor);
        l_noise->line_width(2.0);
        l_noise->color("gray");
        l_noise->line_style("--");
        l_noise->display_name("Noise Floor");
    }

    // 3. Manual Threshold Line (Replacing yline)
    std::vector<double> x_line = {1.0, (double)n_steps};
    std::vector<double> y_line = {0.9, 0.9};
    auto l_cut = plot(x_line, y_line);
    l_cut->color("black");
    l_cut->line_style(":");
    l_cut->line_width(1.5);
    l_cut->display_name("Consensus Threshold (0.9)");

    // --- ANNOTATIONS ---
    title("Stability Paths: Evolution of Phi Matrix");
    xlabel("Number of Dummies (T)");
    ylabel("Stability Score (Phi)");
    ylim({-0.05, 1.05});
    grid(on);

    legend()->location(legend::general_alignment::bottomright);
    gca()->font_size(14.0);
    show();
}

