void plotFDPMatrix(const Eigen::MatrixXd& FDP_mat, double target_alpha = 0.1) {
    using namespace matplot;

    std::size_t n_steps = FDP_mat.rows();
    std::size_t n_thresholds = FDP_mat.cols();

    // X-Axis: T
    std::vector<double> t_steps(n_steps);
    std::iota(t_steps.begin(), t_steps.end(), 1.0);

    auto f = figure(true);
    f->size(1200, 700);
    hold(on);

    // --- Plot Curves for specific Voting Thresholds ---
    // We plot Loose (0.5), Medium (0.75), and Strict (0.95)
    // Assuming columns map to [0.5 ... 0.95]
    std::vector<int> cols_to_plot = {0, static_cast<int>(n_thresholds/2), (int)n_thresholds - 1};
    std::vector<double> v_labels = {0.50, 0.75, 0.95};
    std::vector<std::string> colors = {"blue", "orange", "magenta"};

    for (size_t i = 0; i < cols_to_plot.size(); ++i) {
        int col_idx = cols_to_plot[i];

        std::vector<double> curve;
        for (size_t t = 0; t < n_steps; ++t) curve.push_back(FDP_mat(t, col_idx));

        auto l = plot(t_steps, curve);
        l->line_width(3.0);
        l->color(colors[i]);

        std::stringstream ss;
        ss << "Voting Threshold v=" << std::fixed << std::setprecision(2) << v_labels[i];
        l->display_name(ss.str());
    }

    // --- Plot Target Alpha Line (The Limit) ---
    std::vector<double> x_lims = {1.0, (double)n_steps};
    std::vector<double> y_lims = {target_alpha, target_alpha};

    auto l_target = plot(x_lims, y_lims);
    l_target->color("red");
    l_target->line_width(2.0);
    l_target->line_style("--");
    l_target->display_name("Target FDR Level (0.1)");

    // --- Annotations ---
    title("FDP Estimation Path: The Plateau Effect");
    xlabel("Number of Dummies (T)");
    ylabel("Estimated FDP");
    grid(on);

    // Add text arrow pointing to the plateau
    // Note: Coordinates are data-relative. Adjust based on your visual check.
    textarrow(30, 0.25, 45, 0.22, "Stagnation Zone");

    legend()->location(legend::general_alignment::right);
    gca()->font_size(15.0);

    show();
}

