void demo_plot_correlation_matrix() {

    // Create a correlation matrix or data
   const std::size_t n = 300;
   const std::size_t p = 500;
   Eigen::MatrixXd X_mat(n, p);

   datagen::detail::generate_ar1_rowwise_matrix(X_mat, n, p, 0.7, std::random_device{}());
   //datagen::detail::generate_standard_normal_matrix(X_mat, n, p, std::random_device{}());
   Eigen::MatrixXd corr_mat = X_mat.transpose() * X_mat;
   corr_mat /= static_cast<double>(n);
   std::vector<std::vector<double>> plt_mat = eigen_to_vector(corr_mat);

   plt::imagesc(plt_mat);
   plt::colorbar();
   plt::show();
}



